import { DavisProblemCategories } from './davis-problem-categories';
import { EntityTags } from './entity-tags';
export interface DavisProblemConfig {
    entityTagsMatch?: 'all' | 'any';
    entityTags?: EntityTags | null;
    /**
     * Trigger on Davis problem open only or also on close.
     */
    onProblemClose?: boolean;
    categories: DavisProblemCategories;
    /**
     * Additional DQL matcher expression to further filter events to match.
     */
    customFilter?: string | null;
    /**
     * Run only after first root cause analysis run completed.
     */
    analysisReady?: boolean;
    /**
     * Triggers only for problems whose severity is this value or more severe. Lower numbers are more severe (1 = critical, 5 = informational), so 3 matches severities 1, 2, and 3.
     */
    severityThreshold?: number | null;
}
